from collections import defaultdict
edges = [('a', 'b'), ('c', 'd'), ('d', 'e')]
adj = defaultdict(set)
nodes = set()
for u, v in edges:
    adj[u].add(v); adj[v].add(u); nodes |= {u, v}
seen = set()
comps = []
for n in sorted(nodes):
    if n in seen:
        continue
    stack = [n]; comp = []
    while stack:
        x = stack.pop()
        if x in seen:
            continue
        seen.add(x); comp.append(x)
        stack.extend(adj[x] - seen)
    comps.append(sorted(comp))
print(sorted(comps, key=lambda c: c[0]))

from collections import defaultdict, deque
edges = [('A', 'B'), ('B', 'C'), ('C', 'D')]
adj = defaultdict(set)
for u, v in edges:
    adj[u].add(v); adj[v].add(u)
q = deque([('A', ['A'])]); seen = {'A'}
path = None
while q:
    n, p = q.popleft()
    if n == 'D':
        path = p; break
    for m in sorted(adj[n]):
        if m not in seen:
            seen.add(m); q.append((m, p + [m]))
print(path, len(path) - 1)

