from collections import defaultdict
edges = [('A', 'B'), ('B', 'C'), ('C', 'D')]
adj = defaultdict(set)
for u, v in edges:
    adj[u].add(v); adj[v].add(u)

def ego(seed, k):
    layer = {seed}; alln = {seed}
    for _ in range(k):
        nxt = set()
        for n in layer:
            nxt |= adj[n]
        nxt -= alln
        alln |= nxt
        layer = nxt
    return sorted(alln)
print(ego('A', 1), ego('A', 2))

